mapper.select:
SELECT COUNT(*) AS cnt
FROM TBL_COM_DEPT D
LEFT JOIN TBL_COM_FACTORY F ON D.FACTORYCD = F.FACTORYCD


        D.DEPTNM LIKE #{search}


        AND D.FACTORYCD = #{factory_cd}


        AND F.PLANTCD = #{plant_cd}

SELECT D.*, F.PLANTCD, F.FACTORYNM, P.PLANTNM
FROM TBL_COM_DEPT D
LEFT JOIN TBL_COM_FACTORY F ON D.FACTORYCD = F.FACTORYCD
LEFT JOIN TBL_COM_PLANT P ON F.PLANTCD = P.PLANTCD


        D.DEPTNM LIKE #{search}


        AND D.FACTORYCD = #{factory_cd}


        AND F.PLANTCD = #{plant_cd}


ORDER BY D.DEPTCD
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

mapper.update:
UPDATE TBL_COM_DEPT
FACTORYCD = #{FACTORYCD}, PAR_DEPTCD = #{PAR_DEPTCD}, DEPTNM = #{DEPTNM}, USEYN = #{USEYN}, EDITUSERID = #{EDITUSERID}, EDITDTM = GETDATE()
WHERE DEPTCD = #{DEPTCD}
